let rawData = $json.text || ($json.message && $json.message.content) || $json.content || "";

const start = rawData.indexOf('{');
const end = rawData.lastIndexOf('}');
const cleanJson = rawData.substring(start, end + 1);

try {
  const data = JSON.parse(cleanJson);
  const liste = data.actualités || data.actualites || [];

  const finalEmbeds = liste.map(item => {
    // Gestion des couleurs
    let color = 3447003; // Bleu par défaut
    const cat = (item.categ || "").toUpperCase();
    if (cat.includes("CRITIQUE")) color = 15158332; // Rouge
    if (cat.includes("IMPORTANT")) color = 15844367; // Jaune

    return {
      title: `📢 ${item.categ || "INFO"} : Veille IA`,
      description: item.résumé || item.resume,
      color: color,
      url: "https://news.google.com/search?q=intelligence%20artificielle"
    };
  });

  // On renvoie un SEUL objet contenant la LISTE des embeds
  return {
    embeds: finalEmbeds
  };

} catch (e) {
  return { error: e.message };
}
